<h2>1.整数类型</h2>
<table>
<thead>
<tr>
<th>长度</th>
<th>符号位</th>
<th>JavaType</th>
<th>Rust风格注解</th>
<th>JT风格注解</th>
</tr>
</thead>
<tbody>
<tr>
<td>1</td>
<td>无</td>
<td><code>byte/Byte</code></td>
<td><code>@Preset.RustStyle.u8</code></td>
<td><code>@Preset.JtStyle.Byte</code></td>
</tr>
<tr>
<td>1</td>
